{
  "version": 1,
  "hooks": {
    "beforeShellExecution": [
      {
        "type": "prompt",
        "matcher": "git commit",
        "prompt": "Pre-Commit Guard: run npm test before committing. If tests fail, fix them and do not commit until the suite is green."
      }
    ]
  }
}

{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "prompt",
            "prompt": "Pre-Commit Guard: if this is a git commit, run npm test first. Block the commit if tests fail."
          }
        ]
      }
    ]
  }
}

{
  "version": 1,
  "hooks": {
    "stop": [
      {
        "type": "prompt",
        "prompt": "Post-Merge Regression Guard: if the last git operation was a merge or rebase, run npm run test:smoke and fix failures before stopping."
      }
    ]
  }
}

{
  "hooks": {
    "Stop": [
      {
        "hooks": [
          {
            "type": "prompt",
            "prompt": "Post-Merge Regression Guard: if a merge or rebase just happened, run npm run test:smoke and fix failures."
          }
        ]
      }
    ]
  }
}

{
  "version": 1,
  "hooks": {
    "afterFileEdit": [
      {
        "type": "prompt",
        "prompt": "Post-Edit Test Guard: run related tests for the files just edited. If tests fail, fix them before continuing other work."
      }
    ]
  }
}

{
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Write|Edit",
        "hooks": [
          {
            "type": "prompt",
            "prompt": "Post-Edit Test Guard: run related tests for the files just edited. If tests fail, fix them before continuing other work."
          }
        ]
      }
    ]
  }
}

{
  "stories": [
    {
      "id": "story-1",
      "title": "Example user story",
      "description": "Replace with your first atomic task",
      "priority": 1,
      "passes": false,
      "inProgress": false
    }
  ]
}
